/// <summary>
/// The <c>ETGForexReportsController</c> class extends the controller to display and run the forex report.
/// </summary>
internal class ETGForexReportsController extends SrsReportRunController
{

}

Method.Source:
/// <summary>
/// Initailzes the controller, sets the print management, assigns parameter values and runs the SRS report.
/// </summary>
/// <param name="_args">
/// The <c>Args</c> object.
/// </param>
public static void main(Args _args)
{
    ETGForexReportsController forexReportsController = new ETGForexReportsController();
    forexReportsController.parmArgs(_args);
    forexReportsController.parmReportName(ssrsReportStr(ETGForexReportCopy, Report));
    forexReportsController.startOperation();
}
